"use client";

import { useMemo, useState, type ReactElement } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";
import {
  BICLUSTER_VIZ_PROBLEM,
  BICLUSTER_VIZ_TECHNIQUES,
  type BiclusterVizTechniqueId,
} from "@/lib/bicluster-viz";
import { RawDataTable } from "./RawDataTable";
import { TermButton } from "@/components/glossary/TermButton";

const SCRAMBLED_ROWS = [2, 0, 3, 1];
const SCRAMBLED_COLS = [2, 3, 0, 1];

type Props = {
  data: TeachingDataset;
  accent?: string;
};

function HeatmapTechnique({ data, accent }: Props) {
  const br = data.bicluster.rowIndices;
  const bc = data.bicluster.colIndices;
  const reorderedRows = [
    ...br,
    ...data.rows.map((_, i) => i).filter((i) => !br.includes(i)),
  ];
  const reorderedCols = [
    ...bc,
    ...data.cols.map((_, i) => i).filter((i) => !bc.includes(i)),
  ];

  return (
    <div className="grid gap-4 md:grid-cols-2">
      <div className="space-y-2">
        <p className="text-xs font-bold uppercase tracking-wide text-[#888]">Before reorder</p>
        <p className="readable text-sm text-[#444]">
          Bicluster cells are scattered — no clear rectangle yet.
        </p>
        <RawDataTable
          data={data}
          accent={accent}
          scrambledRowOrder={SCRAMBLED_ROWS}
          scrambledColOrder={SCRAMBLED_COLS}
          highlightRows={br}
          highlightCols={bc}
          dimOutside={false}
          animateCells={false}
        />
      </div>
      <div className="space-y-2">
        <p className="text-xs font-bold uppercase tracking-wide text-[#888]">After reorder</p>
        <p className="readable text-sm text-[#444]">
          Same data — bicluster rows and columns slide together into a bright block.
        </p>
        <RawDataTable
          data={data}
          accent={accent}
          scrambledRowOrder={reorderedRows}
          scrambledColOrder={reorderedCols}
          highlightRows={br}
          highlightCols={bc}
          dimOutside
          animateCells={false}
        />
      </div>
    </div>
  );
}

function ParallelTechnique({ data, accent }: Props) {
  const color = accent ?? data.theme.accent;
  const br = new Set(data.bicluster.rowIndices);
  const bc = new Set(data.bicluster.colIndices);
  const w = 320;
  const h = 200;
  const padX = 36;
  const padY = 24;
  const innerW = w - padX * 2;
  const innerH = h - padY * 2;
  const colCount = data.cols.length;

  const xAt = (ci: number) => padX + (ci / (colCount - 1)) * innerW;
  const yAt = (v: number) => padY + innerH - ((v - 1) / 4) * innerH;

  return (
    <div className="overflow-x-auto">
      <svg viewBox={`0 0 ${w} ${h}`} className="w-full max-w-md border-2 border-black bg-white">
        {data.cols.map((label, ci) => {
          const x = xAt(ci);
          const inBicluster = bc.has(ci);
          return (
            <g key={label}>
              <line
                x1={x}
                y1={padY}
                x2={x}
                y2={h - padY}
                stroke={inBicluster ? "#FFE600" : "#CCC"}
                strokeWidth={inBicluster ? 3 : 1}
              />
              <text
                x={x}
                y={h - 6}
                textAnchor="middle"
                fontSize={9}
                fontWeight={inBicluster ? 700 : 400}
                fill="#0A0A0A"
              >
                {label.length > 8 ? label.slice(0, 7) + "…" : label}
              </text>
            </g>
          );
        })}
        {data.rows.map((rowLabel, ri) => {
          const inBicluster = br.has(ri);
          const points = data.matrix[ri]
            .map((v, ci) => `${xAt(ci)},${yAt(v)}`)
            .join(" ");
          return (
            <g key={rowLabel}>
              <polyline
                points={points}
                fill="none"
                stroke={inBicluster ? color : "#AAA"}
                strokeWidth={inBicluster ? 2.5 : 1.2}
                opacity={inBicluster ? 1 : 0.45}
              />
              {data.matrix[ri].map((v, ci) =>
                bc.has(ci) && br.has(ri) ? (
                  <circle
                    key={ci}
                    cx={xAt(ci)}
                    cy={yAt(v)}
                    r={4}
                    fill={color}
                    stroke="#000"
                    strokeWidth={1}
                  />
                ) : null,
              )}
              <text x={4} y={yAt(data.matrix[ri][0]) + 3} fontSize={9} fontWeight={700}>
                {rowLabel}
              </text>
            </g>
          );
        })}
      </svg>
      <p className="mt-2 readable text-sm text-[#444]">
        Yellow axes = bicluster columns (
        {bc.size > 0
          ? [...bc].map((i) => data.cols[i]).join(" & ")
          : "highlighted"}
        ). Bold lines = bicluster rows — they spike together on those axes.
      </p>
    </div>
  );
}

function BipartiteTechnique({ data, accent }: Props) {
  const color = accent ?? data.theme.accent;
  const br = data.bicluster.rowIndices;
  const bc = data.bicluster.colIndices;
  const w = 360;
  const h = 220;
  const leftX = 56;
  const rightX = w - 56;
  const rowYs = data.rows.map((_, i) => 36 + (i / (data.rows.length - 1)) * (h - 72));
  const colYs = data.cols.map((_, i) => 36 + (i / (data.cols.length - 1)) * (h - 72));

  const edges = useMemo(() => {
    const list: { ri: number; ci: number; strong: boolean }[] = [];
    for (let ri = 0; ri < data.rows.length; ri++) {
      for (let ci = 0; ci < data.cols.length; ci++) {
        const inBlock = br.includes(ri) && bc.includes(ci);
        if (inBlock || data.matrix[ri][ci] >= 4) {
          list.push({ ri, ci, strong: inBlock });
        }
      }
    }
    return list;
  }, [data, br, bc]);

  return (
    <div className="overflow-x-auto">
      <svg viewBox={`0 0 ${w} ${h}`} className="w-full max-w-md border-2 border-black bg-white">
        <text x={leftX} y={16} textAnchor="middle" fontSize={10} fontWeight={700}>
          {data.rowLabel}
        </text>
        <text x={rightX} y={16} textAnchor="middle" fontSize={10} fontWeight={700}>
          {data.colLabel}
        </text>
        {edges.map(({ ri, ci, strong }) => (
          <line
            key={`${ri}-${ci}`}
            x1={leftX}
            y1={rowYs[ri]}
            x2={rightX}
            y2={colYs[ci]}
            stroke={strong ? color : "#DDD"}
            strokeWidth={strong ? 2.5 : 0.8}
            opacity={strong ? 0.85 : 0.35}
          />
        ))}
        {data.rows.map((label, i) => {
          const active = br.includes(i);
          return (
            <g key={label}>
              <circle
                cx={leftX}
                cy={rowYs[i]}
                r={active ? 10 : 7}
                fill={active ? color : "#F0F0F0"}
                stroke="#000"
                strokeWidth={2}
              />
              <text
                x={leftX - 18}
                y={rowYs[i] + 4}
                textAnchor="end"
                fontSize={10}
                fontWeight={active ? 700 : 400}
              >
                {label}
              </text>
            </g>
          );
        })}
        {data.cols.map((label, i) => {
          const active = bc.includes(i);
          return (
            <g key={label}>
              <circle
                cx={rightX}
                cy={colYs[i]}
                r={active ? 10 : 7}
                fill={active ? "#FFE600" : "#F0F0F0"}
                stroke="#000"
                strokeWidth={2}
              />
              <text
                x={rightX + 18}
                y={colYs[i] + 4}
                textAnchor="start"
                fontSize={10}
                fontWeight={active ? 700 : 400}
              >
                {label}
              </text>
            </g>
          );
        })}
      </svg>
      <p className="mt-2 readable text-sm text-[#444]">
        Thick edges = bicluster membership ({data.bicluster.label}). Faint edges = other strong
        ties elsewhere in the matrix.
      </p>
    </div>
  );
}

const TECHNIQUE_VIEWS: Record<
  BiclusterVizTechniqueId,
  (props: Props) => ReactElement
> = {
  heatmap: HeatmapTechnique,
  parallel: ParallelTechnique,
  bipartite: BipartiteTechnique,
};

export function BiclusterVizPanel({ data, accent = "#FFE600" }: Props) {
  const [active, setActive] = useState<BiclusterVizTechniqueId>("heatmap");
  const technique = BICLUSTER_VIZ_TECHNIQUES.find((t) => t.id === active)!;
  const View = TECHNIQUE_VIEWS[active];

  return (
    <div className="space-y-5">
      <div className="border-2 border-black bg-[#FFF9D6] p-4 md:p-5">
        <p className="text-xs font-bold uppercase tracking-wide text-[#888]">Core challenge</p>
        <h3 className="mt-1 text-lg font-bold">{BICLUSTER_VIZ_PROBLEM.headline}</h3>
        <p className="readable mt-2 text-[15px] text-[#333]">{BICLUSTER_VIZ_PROBLEM.body}</p>
      </div>

      <div>
        <p className="text-xs font-semibold text-[#5c5c5c]">Three visualization techniques</p>
        <div className="mt-2 flex flex-col gap-2 sm:flex-row sm:flex-wrap">
          {BICLUSTER_VIZ_TECHNIQUES.map((t) => {
            const selected = active === t.id;
            return (
              <button
                key={t.id}
                onClick={() => setActive(t.id)}
                className="flex-1 border-2 border-black px-3 py-2.5 text-left text-sm font-bold transition-colors sm:min-w-[140px] sm:flex-none"
                style={{
                  backgroundColor: selected ? accent : "#FFF",
                  color: selected ? "#0A0A0A" : "#0A0A0A",
                }}
              >
                <span className="block">{t.title}</span>
                <span className="block text-[11px] font-normal opacity-70">{t.subtitle}</span>
              </button>
            );
          })}
        </div>
      </div>

      <AnimatePresence mode="wait">
        <motion.div
          key={active}
          initial={{ opacity: 0, y: 8 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -6 }}
          transition={{ duration: 0.2 }}
          className="border-2 border-black bg-white p-4 md:p-5"
        >
          <p className="text-sm font-bold">
            <TermButton termId={technique.termId}>{technique.title}</TermButton>
          </p>
          <p className="readable mt-2 text-[15px] text-[#444]">{technique.description}</p>
          <div className="mt-4">
            <View data={data} accent={accent} />
          </div>
        </motion.div>
      </AnimatePresence>

      <div className="grid gap-2 md:grid-cols-3">
        {BICLUSTER_VIZ_TECHNIQUES.map((t) => (
          <div
            key={t.id}
            className="border-2 border-black px-3 py-2 text-xs"
            style={{
              backgroundColor: active === t.id ? `${accent}22` : "#FAFAFA",
            }}
          >
            <span className="font-bold">{t.title}</span>
            <span className="text-[#666]"> — {t.subtitle}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
